using System.ComponentModel;
using System.Net;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the chat client through the MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var notepad = new NotepadTool();
var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic, you:
        1. Search the web for relevant information using the search tool (make multiple varied queries).
        2. Save important findings as notes using the note-taking tool.
        3. After gathering enough information, retrieve all your notes.
        4. Produce a well-structured summary with key findings and sources.
        Be thorough but concise. Always cite your sources.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and summarizing findings.",
    tools: tools);

// --- Get the research topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent ---
var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

var response = await agent.RunAsync(
    $"Research this topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine("─── Research Summary ───\n");
Console.WriteLine(response.Text);

if (response.Usage is { } usage)
{
    Console.WriteLine($"\n📊 Tokens — input: {usage.InputTokenCount}, output: {usage.OutputTokenCount}, total: {usage.TotalTokenCount}");
}

// ═══════════════════════════════════════════════════════════════
// Tools
// ═══════════════════════════════════════════════════════════════

/// <summary>Simulates web search by fetching real pages via Bing.</summary>
static class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for a query and return relevant text snippets with source URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);

            var results = ParseResults(html);
            if (results.Count == 0)
            {
                return $"No results found for: {query}";
            }

            return $"Search results for \"{query}\":\n\n" +
                   string.Join("\n\n", results.Take(5));
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}";
        }
    }

    private static List<string> ParseResults(string html)
    {
        var results = new List<string>();

        // Extract result snippets from DuckDuckGo HTML results
        var snippetTag = "class=\"result__snippet\"";
        var linkTag = "class=\"result__a\"";
        var idx = 0;

        while ((idx = html.IndexOf(snippetTag, idx, StringComparison.Ordinal)) >= 0)
        {
            idx += snippetTag.Length;
            var start = html.IndexOf('>', idx);
            if (start < 0) break;
            start++;
            var end = html.IndexOf('<', start);
            if (end < 0) break;

            var snippet = WebUtility.HtmlDecode(html[start..end]).Trim();
            if (string.IsNullOrWhiteSpace(snippet)) continue;

            // Try to find the associated link
            var linkSearch = html.LastIndexOf(linkTag, idx, StringComparison.Ordinal);
            var href = "";
            if (linkSearch >= 0)
            {
                var hrefStart = html.IndexOf("href=\"", linkSearch, StringComparison.Ordinal);
                if (hrefStart >= 0 && hrefStart < idx)
                {
                    hrefStart += 6;
                    var hrefEnd = html.IndexOf('"', hrefStart);
                    if (hrefEnd >= 0)
                    {
                        href = WebUtility.HtmlDecode(html[hrefStart..hrefEnd]);
                    }
                }
            }

            var entry = string.IsNullOrEmpty(href)
                ? $"- {snippet}"
                : $"- {snippet}\n  Source: {href}";

            results.Add(entry);
        }

        return results;
    }
}

/// <summary>Lets the agent save and retrieve research notes.</summary>
class NotepadTool
{
    private readonly List<string> _notes = [];

    [Description("Save an important finding or fact as a note for later reference.")]
    public string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0) return "No notes saved yet.";
        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

